# Category: business_logic_flaw

class PaymentError(Exception):
    pass

def process_transaction(payment_details, amount):
    # Simulated payment processing logic.
    # Normally, you'd integrate with a payment gateway here.
    if not payment_details.get("card_number") or amount <= 0:
        raise PaymentError("Invalid payment details or amount.")
    # Simulate payment processing and return a success flag.
    return {"status": "success", "amount_charged": amount}

def process_payment(user, cart_items, payment_details):
    role = user.get("role", "basic").lower()
    discount_map = {
        "enterprise": 0.30,
        "premium": 0.15,
        "basic": 0.0
    }
    discount_rate = discount_map.get(role, 0.0)

    total = 0
    for item in cart_items:
        price = item.get("price", 0)
        quantity = item.get("quantity", 1)
        total += price * quantity

    discount_amount = total * discount_rate
    final_total = total - discount_amount

    try:
        result = process_transaction(payment_details, final_total)
    except PaymentError as e:
        return {"status": "failure", "error": str(e)}

    return {
        "status": "success",
        "initial_total": total,
        "discount_rate": discount_rate,
        "discount_amount": discount_amount,
        "amount_charged": final_total,
        "transaction_result": result
    }

